(function(){if(window.location.pathname.startsWith('/nalog/')||window.location.pathname.startsWith('/admin/')){return;}
const pollUrl='/ponuda/status/';const pollIntervalMs=2500;const LIVE_OFFER_ACTIVE_KEY='live_offer_active_session';let lastOfferVersion=null;let activeOffer=null;let overlay=null;let countdownTimer=null;let timerSeconds=0;let pollCsrfToken=null;function storePollCsrf(data){if(data&&data.csrf_token){pollCsrfToken=data.csrf_token;const meta=document.querySelector('meta[name="csrf-token"]');if(meta){meta.content=data.csrf_token;}}}
function hideCompetingPopups(){const recoveryOverlay=document.getElementById('cartRecoveryOverlay');if(recoveryOverlay){recoveryOverlay.classList.remove('is-visible');recoveryOverlay.hidden=true;}
document.querySelectorAll('.site-popup-overlay[data-popup-id]').forEach(function(popup){popup.classList.remove('is-visible');popup.hidden=true;});const upsellOverlay=document.getElementById('upsellPopupOverlay');if(upsellOverlay){upsellOverlay.classList.remove('is-visible');upsellOverlay.hidden=true;}}
function markLiveOfferActive(){try{sessionStorage.setItem(LIVE_OFFER_ACTIVE_KEY,'1');}catch(err){}}
function clearLiveOfferActive(){try{sessionStorage.removeItem(LIVE_OFFER_ACTIVE_KEY);}catch(err){}}
function dismissCartRecoveryOverlay(){hideCompetingPopups();fetch('/korpa/podsjetnik/zatvori/',{method:'POST',headers:{'X-CSRFToken':readCsrfToken(),'X-Requested-With':'XMLHttpRequest','Content-Type':'application/x-www-form-urlencoded',},credentials:'same-origin',body:'csrfmiddlewaretoken='+encodeURIComponent(readCsrfToken()),}).catch(function(){});}
function showCartToast(message){if(typeof window.showCartToast==='function'){window.showCartToast(message);return;}
let toast=document.querySelector('.cart-toast');if(!toast){toast=document.createElement('p');toast.className='cart-toast';document.body.appendChild(toast);}
toast.textContent=message;toast.classList.add('cart-toast--visible');window.setTimeout(function(){toast.classList.remove('cart-toast--visible');},2200);}
async function parseJsonResponse(response){const text=await response.text();try{return JSON.parse(text);}catch(err){if(response.status===403){throw new Error('Sesija je istekla. Osvježite stranicu i pokušajte ponovo.');}
throw new Error('Dodavanje u korpu nije uspjelo.');}}
function readCsrfToken(){if(pollCsrfToken){return pollCsrfToken;}
const meta=document.querySelector('meta[name="csrf-token"]');if(meta&&meta.content){return meta.content;}
const match=document.cookie.match(/(?:^|;\s*)csrftoken=([^;]+)/);if(match){return decodeURIComponent(match[1]);}
const input=document.querySelector('input[name="csrfmiddlewaretoken"]');if(input&&input.value){return input.value;}
return'';}
function buildOfferPostBody(form){const csrf=readCsrfToken();if(!csrf){throw new Error('Sigurnosni token nije dostupan. Osvježite stranicu.');}
const body=new URLSearchParams(new FormData(form));body.set('csrfmiddlewaretoken',csrf);body.set('stay','1');return{csrf:csrf,body:body};}
function escapeHtml(value){return String(value||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function formatTimer(totalSeconds){const seconds=Math.max(0,totalSeconds|0);const minutes=Math.floor(seconds/60);const secs=seconds%60;return String(minutes)+':'+String(secs).padStart(2,'0');}
function stopCountdown(){if(countdownTimer){window.clearInterval(countdownTimer);countdownTimer=null;}}
function startCountdown(seconds){stopCountdown();timerSeconds=Math.max(0,seconds|0);const timerEl=overlay?overlay.querySelector('[data-live-offer-timer]'):null;if(!timerEl)return;timerEl.textContent=formatTimer(timerSeconds);countdownTimer=window.setInterval(function(){timerSeconds=Math.max(0,timerSeconds-1);timerEl.textContent=formatTimer(timerSeconds);if(timerSeconds<=0){stopCountdown();}},1000);}
function closeOverlay(){if(!overlay)return;overlay.classList.remove('is-visible');overlay.hidden=true;document.body.classList.remove('popup-open');stopCountdown();}
function openOverlay(){if(!overlay)return;hideCompetingPopups();markLiveOfferActive();overlay.hidden=false;requestAnimationFrame(function(){overlay.classList.add('is-visible');});document.body.classList.add('popup-open');if(activeOffer){startCountdown(activeOffer.timer_seconds);}}
function buildVariationOptions(offer){if(!offer.has_variations){return'<input type="hidden" name="variation_id" value="">';}
const options=['<option value="">Izaberite varijaciju</option>'];offer.variations.forEach(function(variation){const price=variation.has_discount?variation.final_price:variation.base_price;options.push('<option value="'+variation.id+'" '+'data-base="'+escapeHtml(variation.base_price)+'" '+'data-final="'+escapeHtml(variation.final_price)+'" '+'data-has-discount="'+(variation.has_discount?'1':'0')+'">'+
escapeHtml(variation.naziv)+' — '+escapeHtml(price)+' KM</option>',);});return'<select name="variation_id" class="live-offer-var-select" id="liveOfferVariation" required>'+
options.join('')+'</select>';}
function buildPricesHtml(offer){if(offer.has_discount){return('<span class="live-offer-price-original" id="liveOfferPriceOriginal">'+
escapeHtml(offer.display_base_price)+' KM</span>'+'<span class="live-offer-price-final" id="liveOfferPriceFinal">'+
escapeHtml(offer.display_final_price)+' KM</span>');}
return'<span class="live-offer-price-final" id="liveOfferPriceFinal">'+
escapeHtml(offer.display_base_price)+' KM</span>';}
function buildOverlayHtml(offer){const promoText=offer.has_discount&&offer.discount_percent?'Dodatni popust od <strong>'+escapeHtml(offer.discount_percent)+'%</strong>':'Posebna ponuda samo za vas';const imageHtml=offer.image_url?'<img src="'+escapeHtml(offer.image_url)+'" alt="'+escapeHtml(offer.product_name)+'" class="live-offer-image" width="240" height="240" loading="eager" decoding="async">':'<div class="live-offer-image-placeholder"></div>';return('<div class="site-popup-overlay live-offer-overlay is-visible" id="liveOfferOverlay">'+'<div class="site-popup site-popup--akcija live-offer-popup" role="dialog" aria-modal="true">'+'<button type="button" class="site-popup-close" data-live-offer-close aria-label="Zatvori">'+'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">'+'<line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>'+'</svg></button>'+'<div class="live-offer-hero">'+'<div class="live-offer-image-wrap">'+imageHtml+'</div>'+'<div class="live-offer-timer-box">'+'<span class="live-offer-timer-label">Ponuda ističe za</span>'+'<span class="live-offer-timer-value" data-live-offer-timer>9:00</span>'+'</div></div>'+'<div class="live-offer-body">'+'<p class="live-offer-kicker">Posebna ponuda</p>'+'<h3 class="live-offer-product-name">'+escapeHtml(offer.product_name)+'</h3>'+'<p class="live-offer-promo">'+promoText+'</p>'+'<div class="live-offer-prices" id="liveOfferPrices">'+buildPricesHtml(offer)+'</div>'+'<form method="post" action="'+escapeHtml(offer.add_url)+'" class="live-offer-form" id="liveOfferForm">'+
buildVariationOptions(offer)+'<button type="submit" class="btn btn-primary site-popup-cta live-offer-cta">Dodaj u korpu</button>'+'</form></div></div></div>');}
function bindOverlayEvents(){if(!overlay)return;overlay.querySelector('[data-live-offer-close]')?.addEventListener('click',dismissOffer);overlay.addEventListener('click',function(e){if(e.target===overlay)dismissOffer();});const variationSelect=overlay.querySelector('#liveOfferVariation');const priceOriginal=overlay.querySelector('#liveOfferPriceOriginal');const priceFinal=overlay.querySelector('#liveOfferPriceFinal');if(variationSelect&&priceFinal){variationSelect.addEventListener('change',function(){const option=variationSelect.options[variationSelect.selectedIndex];if(!option||!option.value)return;const hasDiscount=option.dataset.hasDiscount==='1';if(hasDiscount&&priceOriginal){priceOriginal.textContent=option.dataset.base+' KM';priceOriginal.hidden=false;priceFinal.textContent=option.dataset.final+' KM';}else if(priceOriginal){priceOriginal.hidden=true;priceFinal.textContent=option.dataset.base+' KM';}});}
const offerForm=overlay.querySelector('#liveOfferForm');if(offerForm){offerForm.addEventListener('submit',async function(e){e.preventDefault();const submitBtn=offerForm.querySelector('button[type="submit"]');if(submitBtn)submitBtn.disabled=true;try{const postData=buildOfferPostBody(offerForm);const response=await fetch(offerForm.action,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded','X-CSRFToken':postData.csrf,'X-Requested-With':'XMLHttpRequest',},credentials:'same-origin',body:postData.body.toString(),});const data=await parseJsonResponse(response);if(!response.ok||!data.ok){throw new Error(data.message||'Dodavanje u korpu nije uspjelo.');}
lastOfferVersion=null;activeOffer=null;clearLiveOfferActive();dismissCartRecoveryOverlay();closeOverlay();if(overlay&&overlay.parentNode){overlay.parentNode.removeChild(overlay);overlay=null;}
showCartToast(data.message);const cartBtn=document.querySelector('.cart-btn');if(cartBtn&&data.cart_count!=null){cartBtn.dataset.cartCount=String(data.cart_count);cartBtn.classList.toggle('cart-btn--has-items',data.cart_count>0);let badge=cartBtn.querySelector('.cart-badge');if(data.cart_count>0){if(!badge){badge=document.createElement('span');badge.className='cart-badge';cartBtn.appendChild(badge);}
badge.textContent=String(data.cart_count);}else if(badge){badge.remove();}}}catch(err){alert(err.message||'Dodavanje u korpu nije uspjelo.');}finally{if(submitBtn)submitBtn.disabled=false;}});}}
async function dismissOffer(){try{await fetch('/ponuda/zatvori/',{method:'POST',headers:{'X-CSRFToken':readCsrfToken(),'X-Requested-With':'XMLHttpRequest','Content-Type':'application/x-www-form-urlencoded',},body:'csrfmiddlewaretoken='+encodeURIComponent(readCsrfToken()),});}catch(err){}
lastOfferVersion=null;clearLiveOfferActive();closeOverlay();}
function renderOffer(offer){const mount=document.getElementById('liveOfferMount');if(!mount)return;const isNew=offer.offer_version!==lastOfferVersion;const wasVisible=overlay&&!overlay.hidden&&overlay.classList.contains('is-visible');if(overlay&&overlay.parentNode){overlay.parentNode.removeChild(overlay);overlay=null;}
mount.innerHTML=buildOverlayHtml(offer);overlay=document.getElementById('liveOfferOverlay');activeOffer=offer;bindOverlayEvents();if(isNew||!wasVisible){openOverlay();}else if(activeOffer){startCountdown(activeOffer.timer_seconds);}
lastOfferVersion=offer.offer_version;}
async function pollOffer(){try{const response=await fetch(pollUrl,{headers:{'X-Requested-With':'XMLHttpRequest'},credentials:'same-origin',});if(!response.ok)return;const data=await response.json();storePollCsrf(data);if(!data.active||!data.offer){if(overlay)closeOverlay();lastOfferVersion=null;activeOffer=null;return;}
if(data.offer.offer_version!==lastOfferVersion){renderOffer(data.offer);}else if(overlay&&activeOffer){activeOffer.timer_seconds=data.offer.timer_seconds;if(overlay.classList.contains('is-visible')){startCountdown(data.offer.timer_seconds);}}}catch(err){}}
document.addEventListener('keydown',function(e){if(e.key==='Escape'&&overlay&&overlay.classList.contains('is-visible')){dismissOffer();}});pollOffer();window.setInterval(pollOffer,pollIntervalMs);})();